def _cleanup_rate_limit_store(current_time, window):
    """Remove expired entries from the rate limit store."""
    keys_to_remove = []
    for key, entries in rate_limit_store.items():
        rate_limit_store[key] = [t for t in entries if current_time - t < window]
        if not rate_limit_store[key]:
            keys_to_remove.append(key)
    for key in keys_to_remove:
        del rate_limit_store[key]


def check_rate_limit(identifier, max_requests):
    """
    Check if the given identifier has exceeded the rate limit.
    Returns (is_allowed, remaining_requests, retry_after_seconds).
    """
    window = app.config['RATE_LIMIT_WINDOW_SECONDS']
    current_time = time.time()

    with rate_limit_lock:
        _cleanup_rate_limit_store(current_time, window)

        if identifier not in rate_limit_store:
            rate_limit_store[identifier] = []

        # Filter to only requests within the current window
        recent_requests = [
            t for t in rate_limit_store[identifier]
            if current_time - t < window
        ]
        rate_limit_store[identifier] = recent_requests

        if len(recent_requests) >= max_requests:
            oldest_in_window = min(recent_requests)
            retry_after = int(window - (current_time - oldest_in_window)) + 1
            return False, 0, retry_after

        rate_limit_store[identifier].append(current_time)
        remaining = max_requests - len(rate_limit_store[identifier])
        return True, remaining, 0


def rate_limit_by_ip(f):
    """Decorator to apply rate limiting by IP address."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        client_ip = request.headers.get('X-Forwarded-For', request.remote_addr)
        if client_ip and ',' in client_ip:
            client_ip = client_ip.split(',')[0].strip()

        ip_key = f"ip:{client_ip}"
        allowed, remaining, retry_after = check_rate_limit(
            ip_key, app.config['RATE_LIMIT_MAX_REQUESTS_PER_IP']
        )

        if not allowed:
            response = jsonify({
                "message": "Too many requests. Please try again later.",
                "retry_after": retry_after
            })
            response.status_code = 429
            response.headers['Retry-After'] = str(retry_after)
            return response

        response = f(*args, **kwargs)
        return response

    return decorated_function


def invalidate_existing_tokens(conn, email):
    """Mark all existing unused tokens for an email as used (single-use enforcement)."""
    conn.execute(
        '''
        UPDATE password_reset_tokens
        SET used = 1, used_at = CURRENT_TIMESTAMP
        WHERE email = ? COLLATE NOCASE AND used = 0
        ''',
        (email.lower(),)
    )


def add_constant_time_delay(start_time, target_duration=0.5):
    """
    Ensure the endpoint takes a consistent amount of time to respond,
    preventing timing-based enumeration attacks.
    """
    elapsed = time.time() - start_time
    remaining = target_duration - elapsed
    if remaining > 0:
        time.sleep(remaining)


@app.route('/api/password-reset/request', methods=['POST'])
@rate_limit_by_ip
def request_password_reset():
    """
    Request a password reset link.
    Always returns the same generic response regardless of whether the email exists.
    """
    start_time = time.time()

    data = request.get_json()
    if not data or 'email' not in data:
        # Still add delay for consistency
        add_constant_time_delay(start_time)
        return jsonify({"message": GENERIC_RESPONSE_MESSAGE}), 200

    email = data['email'].strip().lower()

    # Basic email format validation
    if not email or '@' not in email or len(email) > 254:
        add_constant_time_delay(start_time)
        return jsonify({"message": GENERIC_RESPONSE_MESSAGE}), 200

    # Per-email rate limiting
    email_key = f"email:{email}"
    email_allowed, _, email_retry_after = check_rate_limit(
        email_key, app.config['RATE_LIMIT_MAX_REQUESTS_PER_EMAIL']
    )

    if not email_allowed:
        # Still return generic response to avoid enumeration,
        # but silently skip sending the email
        add_constant_time_delay(start_time)
        return jsonify({"message": GENERIC_RESPONSE_MESSAGE}), 200

    conn = get_db()
    try:
        # Check if user exists
        user = conn.execute(
            'SELECT id, email FROM users WHERE email = ? COLLATE NOCASE',
            (email,)
        ).fetchone()

        if user:
            # Invalidate any existing unused tokens for this email
            invalidate_existing_tokens(conn, email)

            # Generate a secure token
            raw_token = generate_secure_token()
            token_hash_value = hash_token(raw_token)

            # Calculate expiration
            expires_at = datetime.utcnow() + timedelta(
                minutes=app.config['RESET_TOKEN_EXPIRY_MINUTES']
            )

            # Store the hashed token in the database
            conn.execute(
                '''
                INSERT INTO password_reset_tokens (email, token_hash, expires_at)
                VALUES (?, ?, ?)
                ''',
                (email, token_hash_value, expires_at.isoformat())
            )
            conn.commit()

            # Build the reset link with the raw (unhashed) token
            reset_link = (
                f"{app.config['BASE_URL']}/reset-password?token={raw_token}"
            )

            # Send the email (non-blocking in production)
            send_reset_email(email, reset_link)
        # If user doesn't exist, we do nothing but still return the same response

    except Exception as e:
        app.logger.error(f"Error during password reset request: {e}")
        conn.rollback()
    finally:
        conn.close()

    # Constant-time response to prevent timing-based enumeration
    add_constant_time_delay(start_time)

    return jsonify({"message": GENERIC_RESPONSE_MESSAGE}), 200


@app.route('/api/password-reset/validate', methods=['POST'])
@rate_limit_by_ip
def validate_reset_token():
    """
    Validate a password reset token without consuming it.
    Used by the frontend to check if a token is valid before showing the reset form.
    """
    data = request.get_json()
    if not data or 'token' not in data:
        return jsonify({"valid": False, "message": "Invalid or expired token."}), 400

    raw_token = data['token'].strip()
    if not raw_token:
        return jsonify({"valid": False, "message": "Invalid or expired token."}), 400

    token_hash_value = hash_token(raw_token)

    conn = get_db()
    try:
        token_record = conn.execute(
            '''
            SELECT id, email, expires_at, used
            FROM password_reset_tokens
            WHERE token_hash = ? AND used = 0
            ''',
            (token_hash_value,)
        ).fetchone()

        if not token_record:
            return jsonify({"valid": False, "message": "Invalid or expired token."}), 400

        # Check expiration
        expires_at = datetime.fromisoformat(token_record['expires_at'])
        if datetime.utcnow() > expires_at:
            # Mark as used since it's expired
            conn.execute(
                'UPDATE password_reset_tokens SET used = 1, used_at = CURRENT_TIMESTAMP WHERE id = ?',
                (token_record['id'],)
            )
            conn.commit()
            return jsonify({"valid": False, "message": "Invalid or expired token."}), 400

        return jsonify({"valid": True, "message": "Token is valid."}), 200

    except Exception as e:
        app.logger.error(f"Error validating reset token: {e}")
        return jsonify({"valid": False, "message": "An error occurred."}), 500
    finally:
        conn.close()


@app.route('/api/password-reset/confirm', methods=['POST'])
@rate_limit_by_ip
def confirm_password_reset():
    """
    Confirm the password reset by providing the token and new password.
    The token is single-use and consumed upon successful reset.
    """
    data = request.get_json()
    if not data or 'token' not in data or 'new_password' not in data:
        return jsonify({"message": "Token and new password are required."}), 400

    raw_token = data['token'].strip()
    new_password = data['new_password']

    # Basic password validation
    if len(new_password) < 8:
        return jsonify({"message": "Password must be at least 8 characters long."}), 400

    if len(new_password) > 128:
        return jsonify({"message": "Password must not exceed 128 characters."}), 400

    token_hash_value = hash_token(raw_token)

    conn = get_db()
    try:
        # Fetch the token record
        token_record = conn.execute(
            '''
            SELECT id, email, expires_at, used
            FROM password_reset_tokens
            WHERE token_hash = ? AND used = 0
            ''',
            (token_hash_value,)
        ).fetchone()

        if not token_record:
            return jsonify({"message": "Invalid or expired reset token."}), 400

        # Check expiration
        expires_at = datetime.fromisoformat(token_record['expires_at'])
        if datetime.utcnow() > expires_at:
            conn.execute(
                'UPDATE password_reset_tokens SET used = 1, used_at = CURRENT_TIMESTAMP WHERE id = ?',
                (token_record['id'],)
            )
            conn.commit()
            return jsonify({"message": "Invalid or expired reset token."}), 400

        email = token_record['email']

        # Hash the new password
        # Using hashlib for MVP; in production use bcrypt or argon2
        import hashlib as hl
        salt = secrets.token_hex(16)
        password_hash = hl.pbkdf2_hmac(
            'sha256',
            new_password.encode('utf-8'),
            salt.encode('utf-8'),
            iterations=600000
        ).hex()
        stored_password = f"pbkdf2:sha256:600000${salt}${password_hash}"

        # Update the user's password
        result = conn.execute(
            'UPDATE users SET password_hash = ? WHERE email = ? COLLATE NOCASE',
            (stored_password, email)
        )

        if result.rowcount == 0:
            return jsonify({"message": "Invalid or expired reset token."}), 400

        # Mark the token as used (single-use)
        conn.execute(
            'UPDATE password_reset_tokens SET used = 1, used_at = CURRENT_TIMESTAMP WHERE id = ?',
            (token_record['id'],)
        )

        # Also invalidate any other tokens for this email
        invalidate_existing_tokens(conn, email)

        conn.commit()

        app.logger.info(f"Password successfully reset for email: {email}")

        return jsonify({"message": "Password has been reset successfully."}), 200

    except Exception as e:
        app.logger.error(f"Error during password reset confirmation: {e}")
        conn.rollback()
        return jsonify({"message": "An error occurred. Please try again."}), 500
    finally:
        conn.close()


